def getTextchunk_info(text,info_map:dict = info_map,threshold:float=0.75):
    """从文本中提取信息块
    
    Args:
        text: 输入文本
        info_map: 信息映射字典
        
    Returns:
        包含信息块的字典
    """
    info_chunks={} 
    result,line_embeddings=get_textLine_embedding(text,info_map,threshold)
    # 遍历 result 的索引位置 
    items = list(result.items())
    for idx in range(len(items)): 
        info_name,start = items[idx] # 如果有下一个索引，就用它作为终点，否则到最后 
        end = items[idx+1][1] if idx+1 < len(items) else len(line_embeddings)
        
        if 0 <= idx < len(line_embeddings): 
            value = " ".join(line_embeddings[start+1:end]) 
            info_chunks[info_name] = value
      
    return info_chunks

def get_textLine_embedding(text:str,info_map:dict,threshold:float):
    """获取文本行的嵌入
    
    Args:
        text: 输入文本
        
    Returns:
        文本行的嵌入
    """
    line_embeddings=[]
    result={}
    for line in text.splitlines():
        # if line=='':
        #     continue
        line=line.strip()
        line_embeddings.append(line)
    # 计算所有行的嵌入(一次计算所有行的嵌入，避免重复调用接口)
    line_embedding = embedding_tool.get_instance().embed_documents(line_embeddings)
    
    for i,embedding in enumerate(line_embedding,start=0):
        for info_name, info_embedding in info_map.items():
            # 计算相似度（使用余弦相似度）
            similarity = embedding_tool.cosine_similarity(embedding, info_embedding)
            if similarity >= threshold:
                result[info_name]=i
                break

    return result,line_embeddings
    
